 * Reads a template file
 * @param {string} name
 * @returns {string}
 */
function readTemplate(name) {
  const templatePath = join(TEMPLATE_DIR, name);
  try {
    return readFile(templatePath, 'utf-8');
  } catch (e) {
    console.error(`Template not found: ${templatePath}`);
    return '';
  }
}

/**
 * Substitutes template variables with data values
 * @param {string} template
 * @param {Object} data
 * @returns {string}
 */
function fillTemplate(template, data) {
  let result = template;
  for (const [key, value] of Object.entries(data)) {
    result = result.replace(new RegExp(`{{${key}}}`, 'g'), value);
  }
  return result;
}

/**
 * Simple CSS minification
 * @param {string} css
 * @returns {string}
 */
function minifyCSS(css) {
  return css
    .replace(/\/\*[\s\S]*?\*\//g, '') // Remove comments
    .replace(/\s+/g, ' ') // Collapse whitespace
    .replace(/\s*([{}:;,])\s*/g, '$1') // Remove spaces around punctuation
    .replace(/\n/g, '') // Remove newlines
    .trim();
}

/**
 * Decodes base64 string to Buffer
 * @param {string} base64
 * @returns {Buffer}
 */
function decodeBase64(base64) {
  // Handle data URLs
  const match = base64.match(/^data:.*?;base64,(.+)$/);
  const data = match ? match[1] : base64;
  return Buffer.from(data, 'base64');
}

/**
 * Escapes HTML special characters
 * @param {string} str
 * @returns {string}
 */
function escapeHTML(str) {
  if (!str) return '';
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

/**
 * Formats a date string
 * @param {string} dateStr
 * @returns {string}
 */
function formatDate(dateStr) {
  try {
    return new Date(dateStr).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  } catch {
    return 'Unknown date';
  }
}

/**
 * Generates a UUID v4
 * @returns {string}
 */
function generateUUID() {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// CLI execution
if (process.argv[1] && process.argv[1].includes('build.js')) {
  console.log('Promptfolio Build Generator');
  console.log('Usage: node src/generator/build.js <input.json>');
  console.log('');
  console.log('This module is designed to be imported, not run directly.');
  console.log('Use the landing page or API to generate portfolios.');
}

