    21→ */
    22→export async function generatePortfolio(portfolio, outputDir = './output') {
    23→  const uuid = generateUUID();
    24→  const portfolioDir = join(outputDir, uuid);
    25→
    26→  // Clean and create output directory
    27→  await rm(portfolioDir, { recursive: true, force: true });
